import React from "react";
import InfoPageLayout from "./InfoPageLayout";

const pageData = {
  title: "Solutions",
  subtitle: "Tailored security solutions for every industry and use case. Protect your organization with enterprise-grade cybersecurity.",
  sections: [
    {
      title: "Industry Solutions",
      description: "Specialized security platforms designed for your industry's unique requirements.",
      gridClass: "info-grid-2",
      grid: [
        {
          title: "Financial Services",
          description: "Protect sensitive financial data with compliance-focused security. Meet PCI-DSS, SOX, and banking regulations with automated compliance monitoring and real-time threat detection.",
          list: [
            "PCI-DSS compliance automation",
            "Fraud detection integration",
            "Real-time transaction monitoring",
            "Regulatory reporting (SOX, GLBA)"
          ],
          cta: { text: "Financial Security →", link: "/solutions/financial" }
        },
        {
          title: "Healthcare",
          description: "HIPAA-compliant security for patient data protection. Safeguard electronic health records (EHR) with encryption, access controls, and audit trails.",
          list: [
            "HIPAA compliance automation",
            "EHR system integration",
            "Patient data encryption",
            "Medical device security"
          ],
          cta: { text: "Healthcare Security →", link: "/solutions/healthcare" }
        },
        {
          title: "Enterprise",
          description: "Comprehensive security for large organizations with complex infrastructure. Protect distributed cloud environments, hybrid clouds, and multi-region deployments.",
          list: [
            "Multi-cloud security posture",
            "Zero-trust implementation",
            "Privileged access management",
            "Security orchestration"
          ],
          cta: { text: "Enterprise Security →", link: "/solutions/enterprise" }
        },
        {
          title: "Small Business",
          description: "Affordable, easy-to-deploy security for growing companies. Get enterprise-grade protection without the enterprise complexity.",
          list: [
            "Managed threat detection",
            "Automated security audits",
            "Employee training modules",
            "24/7 security monitoring"
          ],
          cta: { text: "Business Security →", link: "/solutions/smb" }
        }
      ]
    },
    {
      title: "Use Case Solutions",
      description: "Targeted protection for specific security challenges.",
      bgColor: "#f8fafc",
      gridClass: "info-grid-3",
      grid: [
        {
          title: "Cloud Security",
          description: "Secure AWS, Azure, GCP, and Kubernetes environments with automated audits and real-time monitoring."
        },
        {
          title: "Application Security",
          description: "RASP, SAST, DAST, and runtime protection for applications at every development stage."
        },
        {
          title: "Identity & Access",
          description: "Zero-trust IAM with biometric authentication, SSO, and privileged access management."
        },
        {
          title: "Data Protection",
          description: "Encryption, tokenization, and data loss prevention across all data stores."
        },
        {
          title: "Network Security",
          description: "Next-gen firewall, intrusion detection, and micro-segmentation for network protection."
        },
        {
          title: "Threat Intelligence",
          description: "Global threat feed integration, threat hunting, and predictive analytics."
        }
      ]
    },
    {
      stats: [
        { value: "500+", label: "Enterprise Clients" },
        { value: "10M+", label: "Threats Blocked" },
        { value: "99.9%", label: "Uptime SLA" },
        { value: "50+", label: "Compliance Frameworks" }
      ]
    }
  ],
  color: "#06b6d4"
};

function Solutions() {
  return <InfoPageLayout {...pageData} />;
}

export default Solutions;
